class Solution:
    def maximumCostSubstring(self, s: str, chars: str, vals: List[int]) -> int:
        char_map = {c: v for c, v in zip(chars, vals)}
        max_cost = 0
        current_cost = 0
        char_count = {c: 0 for c in chars}

        for c in s:
            if c in char_map:
                current_cost += char_map[c]
                char_count[c] += 1
            else:
                current_cost += ord(c) - ord('a') + 1
            max_cost = max(max_cost, current_cost)
            for c in char_count:
                current_cost -= min(char_count[c], char_map[c])
                char_count[c] -= min(char_count[c], char_map[c])
        return max_cost
